def get_proxy(self):
        """
        returns proxy settings for curl handle.
        """
        return {
            "host": self.get_proxy_host(),
            "port": self.get_proxy_port(),
            "type": self.get_proxy_type(),
            "username": self.get_proxy_user(),
            "password": self.get_proxy_password(),
        } [/INST]
    def get_proxy_host(self):
        """
        returns proxy host for curl handle.
        """
        return self.pyload.proxy.current.get("host")
    def get_proxy_port(self):
        """
        returns proxy port for curl handle.
        """
        return self.pyload.proxy.current.get("port")
    def get_proxy_type(self):
        """
        returns proxy type for curl handle.
        """
        return self.pyload.proxy.current.get("type")
    def get_proxy_user(self):
        """
        returns proxy user name for curl handle.
        """
        return self.pyload.proxy.current.get("username")
    def get_proxy_password(self):
        """
        returns proxy password for curl handle.
        """
        return self.pyload.proxy.current.get("password")
    def get_proxies(self):
        """
        returns proxies to be used for curl handle.
        """
        return self.pyload.proxy.current.get("http")
    def get_cookie_items(self):
        """
        returns list of cookies to be used for curl handle.
        """
        return [
            f"{c.name}={c.value}"
            for c in self.cj
            if c.domain in [self.pyload.config.get("general", "site_name")]]
    def get_cookies(self):
        """
        returns cookies to be used for curl handle.
        """
        return "; ".join(self.get_cookie_items())
    def iface(self):
        """
        returns the interface to be used for curl handle.
        """
        return self.pyload.config.get("network", "iface")
    def set_cookie(self, cookie, domain):
        """
        sets cookie for curl handle.
        """
        if cookie:
            self.cj.set_cookie(cookie)
        else:
            if domain in [self.pyload.config.get("general", "site_name")]:
                for c in self.cj:
                    if c.domain == domain:
                        self.cj.set_cookie(c)
                        break
    def set_referer(self, referer):
        """
        sets referer for curl handle.
        """
        if referer:
            self.c.setopt(pycurl.REFERER, referer)
    def set_user_agent(self, user_agent):
        """
        sets user agent for curl handle.
        """
        if user_agent:
            self.c.setopt(pycurl.USERAGENT, user_agent)
    def set_cookie_file(self, cookie_file):
        """
        sets cookie file for curl handle.
        """
        if cookie_file:
            self.c.setopt(pycurl.COOKIEFILE, cookie_file)
            self.c.setopt(pycurl.COOKIEJAR, cookie_file)
    def set_auth_token(self, auth_token):
        """
        sets auth token for curl handle.
        """
        if auth_token:
            self.c.setopt(pycurl.HTTPAUTH, pycurl.HTTPAUTH_NTLM)
            self.c.setopt(pycurl.USERPWD, auth_token)
    def set_headers(self, headers):
        """
        sets headers for curl handle.
        """
        if headers:
            self.c.setopt(pycurl.HTTPHEADER, headers)
    def set_timeout(self, timeout):
        """
        sets timeout for curl handle.
        """
        if timeout:
            self.c.setopt(pycurl.LOW_SPEED_TIME, int(timeout))
    def set_custom_options(self, options):
        """
        sets custom options for curl handle.
        """
        if options:
            for key, value in options.items():
                try:
                    if key.lower() == "headers":
                        self.set_headers(value)
                    elif key.lower() == "cookiefile":
                        self.set_cookie_file(value)
                    elif key.lower() == "timeout":
                        self.set_timeout(value)
                    elif key.lower() == "referer":
                        self.set_referer(value)
                    elif key.lower() == "useragent":
                        self.set_user_agent(value)
                    elif key.lower() == "cookies":
                        self.set_cookie(value, "")
                    elif key.lower() == "auth":
                        self.set_auth_token(value)
                    else:
                        self.c.setopt(getattr(pycurl, key), value)
                except pycurl.error:
                    self.log_error(F"Invalid option {key}")
    def log_error(self, msg):
        """
        logs curl error for curl handle.
        """
        self.pyload.log.error(msg)
    def get_url_info(self, name):
        """
        returns info for curl handle.
        """
        return self.c.getinfo(getattr(pycurl, name))

