def _extension_element_from_element_tree(element_tree):
    """
    :param element_tree: An ElementTree instance
    :return: An ExtensionElement instance
    """
    if not isinstance(element_tree, ElementTree.Element):
        raise ValueError("Expecting an ElementTree.Element")
    if element_tree.tag[0] == "{":
        tag = element_tree.tag.rsplit("}", 1)[1]
    else:
        tag = element_tree.tag
    extension_element = ExtensionElement(tag, namespace=None)
    for child in list(element_tree):
        if child.tag[0] == "{":
            namespace = child.tag.split("}", 1)[0][1:]
        else:
            namespace = None
        value = child.text
        if value is not None:
            value = value.strip()
        if child.tag == "{%s}must_understand" % SOAP.ENV:
            extension_element.mustunderstand = value
        elif child.tag == "{%s}must_understand" % SOAP.ENV:
            extension_element.actor = value
        else:
            if namespace is None:
                namespace = None
            extension_element.children.append((namespace, tag, value))
    return extension_element
def instanciate_class(element_tree, modules):
    """
    :param element_tree: An ElementTree instance
    :return: An instance of a class
    """
    if not isinstance(element_tree, ElementTree.Element):
        raise ValueError("Expecting an ElementTree.Element")
    if element_tree.tag[0] == "{":
        tag = element_tree.tag.rsplit("}", 1)[1]
    else:
        tag = element_tree.tag
    class_dict = {}
    for child in element_tree:
        if child.tag[0] == "{":
            namespace = child.tag.split("}", 1)[0][1:]
        else:
            namespace = None
        value = child.text
        if value is not None:
            value = value.strip()
        if namespace is None:
            namespace = None
        class_dict[child.tag] = value
    for m in modules:
        try:
            return m.class_instances_from_elements(tag, class_dict)
        except ValueError:
            pass
    return None
def open_soap_envelope_file(file_name):
    """
    :param file_name: XML file name
    :return: dictionary with two keys "body"/"header"
    """
    try:
        with open(file_name, "r") as fd:
            envelope = ElementTree.fromstring(fd.read())
    except Exception as exc:
        raise XmlParseError("%s" % exc)
    assert envelope.tag == '{%s}Envelope' % soapenv.NAMESPACE
    assert len(envelope) >= 1
    content = {"header": [], "body": None}
    for part in envelope:
        if part.tag == '{%s}Body' % soapenv.NAMESPACE:
            assert len(part) == 1
            content["body"] = ElementTree.tostring(part[0], encoding="UTF-8")
        elif part.tag == "{%s}Header" % soapenv.NAMESPACE:
            for item in part:
                content["header"].append(ElementTree.tostring(item, encoding="UTF-8"))
    return content
def soap_fault_from_string(text):
    """
    :param text: a SOAP fault message
    :return: a dictionary with the keys:
        - faultcode
        - faultstring
        - faultactor
        - detail
        - any
    """
    envelope = ElementTree.fromstring(text)
    assert envelope.tag == '{%s}Envelope' % soapenv.NAMESPACE
    assert len(envelope) >= 1
    assert envelope[0].tag == '{%s}Body' % soapenv.NAMESPACE
    assert len(envelope[0]) == 1
    part = envelope[0][0]
    return soap_fault_from_element_tree(part)
def soap_fault_from_element_tree(element_tree):
    """
    :param element_tree: An ElementTree instance
    :return: a dictionary with the keys:
        - faultcode
        - faultstring
        - faultactor
        - detail
        - any
    """
    if not isinstance(element_tree, ElementTree.Element):
        raise ValueError("Expecting an ElementTree.Element")
    if element_tree.tag[0] == "{":
        tag = element_tree.tag.rsplit("}", 1)[1]
    else:
        tag = element_tree.tag
    if tag != "Fault":
        raise ValueError("Expecting an ElementTree.Element with tag Fault")
    fault = {}
    for child in element_tree:
        if child.tag[0] == "{":
            namespace = child.tag.split("}", 1)[0][1:]
        else:
            namespace = None
        value = child.text
        if value is not None:
            value = value.strip()
        if child.tag == "faultcode":
            fault["faultcode"] = value
        elif child.tag == "faultstring":
            fault["faultstring"] = value
        elif child.tag == "faultactor":
            fault["faultactor"] = value
        elif child.tag == "detail":
            fault["detail"] = ElementTree.tostring(child)
        else:
            if namespace is None:
                namespace = None
            if namespace not in fault:
                fault[namespace] = {}
            if tag not in fault[namespace]:
                fault[namespace][tag] = []
            fault[namespace][tag].append(value)
    return fault
def soap_fault_from_xmls(xmls):
    """
    :param xmls: a list of XML strings
    :return: a list of soap faults
    """
    return [soap_fault_from_string(xml) for xml in xmls]
def soap_faults_from_file(file_name):
    """
    :param file_name: XML file name
    :return: a list of soap faults
    """
    try:
        with open(file_name, "r") as fd:
            return soap_faults_from_xmls(fd.read())
    except Exception as exc:
        raise XmlParseError("%s" % exc)
def soap_faults_from_xmls(xmls):
    """
    :param xmls: a list of XML strings
    :return: a list of soap faults
    """
    return [soap_fault_from_string(xml) for xml in xmls]
