class NotificationPlugin(BasePlugin):

    __version__ = '0.0.1'

    def __init__(self, app, plugin_name):
        super().__init__(app, plugin_name)
        self.bus = None
        self.scheduler = None
        self.notifications = None
        self.send_changed = False
        self.notification_job = None

    def start(self):
        self.bus = self.app.events.bus
        self.scheduler = self.app.scheduler
        self.notifications = self.app.notifications
        self.bus.subscribe('user_attr_changed', self.user_attr_changed)
        self.bus.subscribe('user_password_changed', self.user_password_changed)
        self.bus.subscribe('access_token_added', self.access_token_added)
        self.scheduler.add_job(self.send_notifications, 'cron', hour=12, max_instances=1)
        self.scheduler.add_job(self.notification_job, 'cron', hour=0, max_instances=1)
        self.bus.subscribe('scheduler_started', self.start_jobs)
        self.bus.subscribe('scheduler_stopped', self.stop_jobs)

    def stop(self):
        self.bus.unsubscribe('user_attr_changed', self.user_attr_changed)
        self.bus.unsubscribe('user_password_changed', self.user_password_changed)
        self.bus.unsubscribe('access_token_added', self.access_token_added)
        self.scheduler.unsubscribe('scheduler_started', self.start_jobs)
        self.scheduler.unsubscribe('scheduler_stopped', self.stop_jobs)
        if self.scheduler.running:
            self.scheduler.unschedule_job(self.notification_job)
            self.scheduler.unschedule_job(self.send_notifications)

    def start_jobs(self, sender):
        self.scheduler.start_job(self.notification_job)
        self.scheduler.start_job(self.send_notifications)

    def stop_jobs(self, sender):
        self.scheduler.stop_job(self.notification_job)
        self.scheduler.stop_job(self.send_notifications)

