class Instance(BaseInstance):
    """Instance class."""

    def __init__(self, *args, **kwargs):
        """Initialize."""
        super().__init__(*args, **kwargs)
        self._state = "stopped"
        self._base_url = f"http://{self.host}:{self.port}"
        self._full_url = self._base_url + "/"

    def start(self):
        """Start the instance."""
        self._state = "starting"
        try:
            self._proc = self.srv.popen(
                [
                    self.srv.cfg.get("instance", "path"),
                    "-m",
                    "uwsgi",
                    "-s",
                    "{}".format(self.srv.cfg.get("instance", "socket")),
                ],
                stdout=DEVNULL,
                stderr=DEVNULL,
            )
        except Exception:
            self.srv.to_log(
                "error starting instance (%s): %s"
                % (self.instance_id, traceback.format_exc())
            )
            self._state = "stopped"
            return
        self._state = "running"

    def stop(self):
        """Stop the instance."""
        self._state = "stopping"
        self._proc.kill()
        self._proc = None
        self._state = "stopped"

    def restart(self):
        """Restart the instance."""
        self.stop()
        self.start()

    def refresh_state(self):
        """Refresh the instance state."""
        if self._state == "starting":
            if self._proc.poll() is not None:
                self._state = "stopped"
        elif self._state == "stopping":
            if self._proc.poll() is None:
                self._state = "starting"
            else:
                self._state = "stopped"
        elif self._state == "running":
            if self._proc.poll() is not None:
                self._state = "stopped"


class InstanceManager(BaseInstanceManager):
    """Instance manager class."""

    def __init__(self, *args, **kwargs):
        """Initialize."""
        super().__init__(*args, **kwargs)
        self.instances = {}

    def get_instance(self, instance_id):
        """Get instance."""
        if instance_id not in self.instances:
            inst = Instance(instance_id, self, self.srv)
            inst.start()
            self.instances[instance_id] = inst
        return self.instances[instance_id]

    def get_instances(self):
        """Get instances."""
        return self.instances

    def create_instance(self, instance_id):
        """Create instance."""
        if instance_id in self.instances:
            return None
        inst = Instance(instance_id, self, self.srv)
        inst.start()
        self.instances[instance_id] = inst
        return inst

    def delete_instance(self, instance_id):
        """Delete instance."""
        if instance_id in self.instances:
            inst = self.instances[instance_id]
            inst.stop()
            del self.instances[instance_id]
            return inst
        return None

    def get_status(self):
        """Get status."""
        data = {}
        for instance_id in self.get_instances():
            data[instance_id] = self.get_instance(instance_id).get_status()
        return data

    def get_instance_status(self, instance_id):
        """Get instance status."""
        if instance_id in self.instances:
            return self.get_instance(instance_id).get_status()
        return {}

    def get_instance_log(self, instance_id):
        """Get instance log."""
        if instance_id in self.instances:
            return self.get_instance(instance_id).get_log()
        return {}


class InstanceManagerController(BaseInstanceManagerController):
    """Instance manager controller class."""

    def __init__(self, *args, **kwargs):
        """Initialize."""
        super().__init__(*args, **kwargs)
        self.mgr = self.app_context.get_resource(InstanceManager)

    @expose("/")
    @expose("/index.html")
    @expose("/index.htm")
    def index(self):
        """Show index."""
        return self.render("instance_index.html", instances=self.mgr.get_instances())

    @expose("/instance/<instance_id>")
    def instance(self, instance_id):
        """Show instance."""
        return self.render(
            "instance.html",
            status=self.mgr.get_instance_status(instance_id),
            log=self.mgr.get_instance_log(instance_id),
        )

    @expose("/delete/<instance_id>")
    def delete(self, instance_id):
        """Delete instance."""
        self.mgr.delete_instance(instance_id)
        return redirect(self.url_for("index"))

    @expose("/create", methods=["POST"])
    def create(self):
        """Create instance."""
        self.mgr.create_instance(str(uuid.uuid4()))
        return redirect(self.url_for("index"))

    @expose("/status")
    def status(self):
        """Show status."""
        return jsonify(self.mgr.get_status())

