        sender_key,
        payload,
    ):
        event = MegolmEvent.parse_event(payload)
        if isinstance(event, (BadEvent, UnknownBadEvent)):
            return event
        device = self.device_store.store[sender_key].get(sender, None)
        if not device:
            return None
        try:
            decrypted_event = event.decrypt(self)
        except EncryptionError:
            return None
        if decrypted_event.session_id in self.outgoing_key_requests:
            logger.info("Found a key request for this session")
            key_request = self.outgoing_key_requests[decrypted_event.session_id]
            if not key_request.one_time_key:
                logger.info(
                    f"Ignoring already used session from {sender} {sender_key}"
                )
                return None
            key_request.one_time_key = False
            self.store.update_outgoing_key_request(key_request)
            self.outgoing_to_device_messages.append(
                key_request.as_cancellation(self.user_id, self.device_id)
            )
        else:
            if self.inbound_group_store.add(event.session):
                self.save_inbound_group_session(event.session)
