        """ get a parameter in the config file
        @str section: section of the configuration file
        @str param: parameter name
        @dict config: configuration of ldapcherry
        @rtype: str
        """
        if section in config.keys() and param in config[section].keys():
            full_param = '[%(section)s]%(param)s' % {
                'section': section,
                'param': param
            }
            return self.template_dir.check_param(full_param,
