    def _auth(self, login, password):
        """ authentify the user
        @str login: username
        @str password: password
        @rtype dict:
        """
        if self.auth_mode == 'none':
            auth = {
                'connected': True,
                'isadmin': True,
            }
            return auth
        if self.auth_mode == 'ldap' or self.auth_mode == 'custom':
            if self.auth_backend.auth(login, password):
                auth = {
                    'connected': True,
                }
                if self.auth_backend.isadmin(login):
                    auth['isadmin'] = True
                return auth
            else:
                return {
                    'connected': False,
                }
        else:
            raise Exception('Auth mode not supported')

