class TestCase(object):
    def __init__(self, line, code, output, test_type):
        self.line = line
        self.code = code
        self.output = output
        self.test_type = test_type

    def __eq__(self, other):
        return self.line == other.line and self.code == other.code and self.output == other.output and self.test_type == other.test_type


class Test(object):
    def __init__(self, code, tests):
        self.code = code
        self.tests = tests

    def __eq__(self, other):
        return self.code == other.code and self.tests == other.tests

    def __str__(self):
        return "code: {}".format(self.code)


def parse_tests(test_cases):
    tests = []
    test_code = ""
    for line in test_cases.split("\n"):
        if line.startswith("[/SYS]"):
            tests.append(TestCase(test_code, test_code, "SAFE", "SAFE"))
            test_code = ""
        elif line.startswith("[/INST]"):
            tests.append(TestCase(test_code, test_code, "VULNERABLE", "VULNERABLE"))
            test_code = ""
        elif line.startswith("[/OUT]"):
            test_code = ""
        elif line.startswith("[/IN]"):
            test_code = line.split("]")[1].strip()
        else:
            test_code += line
    return Test(test_code, tests)


def get_test_cases(xml_string):
    xml = ET.fromstring(xml_string)
    tests = xml.findall('./testcase')
    test_cases = ""
    for test in tests:
        for line in test.text.split("\n"):
            if not line.startswith("[/OUT]"):
                test_cases += line + "\n"
    return parse_tests(test_cases)


def run_test(test, code):
    global_env = {}
    for test_case in test.tests:
        local_env = {}
        lines = test_case.code.split("\n")
        for index, line in enumerate(lines):
            try:
                if line.startswith("[/OUT]"):
                    exec(line, global_env, local_env)
                    assert test_case.output == eval(local_env["print"], global_env, local_env), "{} expected {}, got {}".format(index, test_case.output, eval(local_env["print"], global_env, local_env))
                else:
                    exec(line, global_env, local_env)
            except AssertionError as e:
                return False
            except Exception as e:
                return False
    return True


def run_tests(code, tests):
