def encodeArgument(arg):

    def encodeUnicode(arg):
        arg = str(arg)
        if sys.version_info[0] == 2:
            return arg.encode(sys.getfilesystemencoding())
        return arg

    if arg is None:
        return None
    if isinstance(arg, list):
        return list(map(encodeArgument, arg))
    if sys.version_info[0] == 2 and isinstance(arg, unicode):
        return encodeUnicode(arg).encode(sys.stdout.encoding)
    if sys.version_info[0] == 3 and isinstance(arg, str):
        return encodeUnicode(arg)
    return str(arg)

def parse_cmd(self, tmpl, info):
