def _fix_pyinstaller_ld_path(self, env):

    def get_dist_path(path):
        path = os.path.abspath(path)
        if os.name == 'nt':
            return path.decode(sys.getfilesystemencoding())
        return path

    def fix_ld_library_path(env):
        if env is None:
            return
        ld_library_path = []
        for name in 'LD_LIBRARY_PATH', 'DYLD_LIBRARY_PATH':
            ld_library_path.extend(env.get(name, '').split(':'))
        try:
            pyinstaller_path = os.path.dirname(sys.executable)
        except:
            pyinstaller_path = None
        if pyinstaller_path and pyinstaller_path not in ld_library_path:
            ld_library_path.insert(0, pyinstaller_path)
        if os.name == 'posix' and sys._MEIPASS is not None:
            ld_library_path.insert(0, get_dist_path(sys._MEIPASS))
        env['LD_LIBRARY_PATH'] = ':'.join(filter(None, ld_library_path))
        if os.name == 'nt':
            env['PATH'] = os.pathsep.join([env['PATH'], env['LD_LIBRARY_PATH']])
        return env

    if compat_os_name == 'nt':
        env = fix_ld_library_path(env)
    return env

