    """
    Returns the reason that event was rejected, or None if there was no
    problem.

    Args:
        event: The event to be rejected
        auth_events (list): list of events that are used as the state at
            the time the event was sent (i.e., as opposed to the current
            state of the room at the time of receiving the event)
        do_sig_check: whether to check signature
        room_version: the state of the room at the time the event
            was sent

    Returns:
        str: The reason that the event was rejected
    """
    event_id = event.event_id
    failures = []

    if not event.is_state() and not event.is_message():
        failures.append(
            "{} was not a valid type, should be "
            "m.room.message or m.room.history_visibility".format(event_id)
        )

    if not event.internal_metadata.is_invite() and not event.room_id:
        failures.append(
            "{} was missing the room_id field".format(event_id)
        )

    if not event.internal_metadata.is_invite() and not event.sender:
        failures.append(
            "{} was missing the sender field".format(event_id)
        )

    if not event.is_state() and not event.is_state_event():
        if not event.prev_events:
            failures.append(
                "{} was missing the prev_events field".format(event_id)
            )

    for key in event.auth_events:
        if key not in auth_events:
            failures.append(
                "{} had an event_id it did not know about in "
                "auth_events".format(event_id)
            )

    if do_sig_check:
        try:
            event_auth.validate_event_content_hash(event)
        except SynapseError as e:
            failures.append(
                "{} had an invalid event_id for its hash: {}".format(
                    event_id, e.msg
                )
            )

        try:
            event_auth.validate_event_content_signed(event, auth_events)
        except SynapseError as e:
            failures.append(
                "{} had an unsigned event in its auth list: {}".format(
                    event_id, e.msg
                )
            )

    if event.prev_events and not event.internal_metadata.is_invite():
        for prev_event_id in event.prev_events:
            try:
                event_auth.check_auth_rules_from_context(
                    prev_event_id,
                    room_version,
                    event.room_id,
                    event.type,
                    event.opcode(),
                    event.room_version,
                    auth_events,
                    do_sig_check,
                )
            except AuthError as e:
                failures.append(
                    "{}'s prev_events had an invalid event: {}".format(
                        event_id, str(e)
                    )
                )

    if failures:
        return (
            "The following auth checks failed: %s" % (
                ", ".join(failures),
            ),
        )
    else:
        return None


