def get_code(code):
    return code.replace("\n", "\\n").replace(" ", "\\s")


def get_code_from_file(file):
    with open(file, "r") as f:
        code = f.read()
        return code.replace("\n", "\\n").replace(" ", "\\s")


def get_import_string(code):
    return "from {} import {}".format(get_import_name(code), get_import_name(code))


def get_import_name(code):
    return hashlib.md5(code.encode("utf-8")).hexdigest()[:12]


def get_import_path(code):
    return "test_code/" + get_import_name(code) + ".py"


def write_import(code):
    with open(get_import_path(code), "w") as f:
        f.write(code)


def load_import(code):
    code_name = get_import_name(code)
    code_path = get_import_path(code)
    if not os.path.exists(code_path):
        write_import(code)
    spec = importlib.util.spec_from_file_location(code_name, code_path)
    code_module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(code_module)
    return code_module


def parse_flags(flags):
    return [flag.strip() for flag in flags.split(",")]


def get_flag_string(flags):
    return ",".join(flags)


def get_flag_string_from_file(flags_file):
    with open(flags_file, "r") as f:
        flags = f.read()
        return get_flag_string(flags)


def get_answer_string(answer):
    return ",".join([str(flag) for flag in answer])


def get_answer_string_from_file(answer_file):
    with open(answer_file, "r") as f:
        answer = f.read()
        return get_answer_string(answer)


def get_answer(code, flags):
