        """Returns a 3-tuple of URL, Proxy Type, and Proxy URL
        for a given URL. Proxy Type is either a value in
        ('http', 'https', 'ftp', None), and Proxy URL is the URL
        to use for proxy, or None if no proxy should be used.
        """
        return connection.get_proxy_info(url, self.proxy, self.proxy_headers)

    def proxy_open(self, method, url, body=None, headers=None):
        return self.proxy_pool.urlopen(method, url, body=body, headers=headers)

    def _set_proxy_headers(self, url):
        """
        Sets self.proxy_headers if using proxy and the URL being
        requested is not on an exception list.
        """
        proxy_type, proxy_url = self.get_proxy_info(url)
        if proxy_url and proxy_url.lower() != 'none':
