def _build_tcp_udp_rule(self, rule, version):
        args = ['--dport', '%s' % (rule.from_port,)]
        if rule.to_port != rule.from_port:
            args.append('--dport', '-:%s' % (rule.to_port,))
        if rule.protocol == 'udp':
            args.insert(0, '-p udp')
        else:
            args.insert(0, '-p tcp')
        return args
    def _build_icmp_rule(self, rule, version):
        if version == 4:
            args = ['-p icmp --icmp-type %s' % rule.from_port]
            if rule.to_port != -1:
                args.append('--icmp-code %s' % rule.to_port)
        else:
            args = ['-p icmpv6 --icmpv6-type %s' % rule.from_port]
            if rule.to_port != -1:
                args.append('--icmpv6-code %s' % rule.to_port)
        return args
    def _do_basic_rules(self, ipv4_rules, ipv6_rules, network_info):
        # Always drop bogus traffic
        ipv4_rules += ['-j DROP']
        ipv6_rules += ['-j DROP']
        # Allow established connections
        ipv4_rules += ['-j ACCEPT --state ESTABLISHED,RELATED']
        ipv6_rules += ['-j ACCEPT --state ESTABLISHED,RELATED']
        # Pass through all traffic from local
        ipv4_rules += ['-o lo -j ACCEPT']
        ipv6_rules += ['-o lo -j ACCEPT']
        # Pass through all traffic from local
        for ip in network_info:
            LOG.debug('Adding IPv4 input/output rules for %s', ip['address'])
            ipv4_rules += ['-i %s -j ACCEPT' % ip['dev']]
            ipv4_rules += ['-o %s -j ACCEPT' % ip['dev']]
            if FLAGS.use_ipv6:
                LOG.debug('Adding IPv6 input/output rules for %s', ip['address'])
                ipv6_rules += ['-i %s -j ACCEPT' % ip['dev']]
                ipv6_rules += ['-o %s -j ACCEPT' % ip['dev']]
        # Drop all other traffic
        ipv4_rules += ['-j REJECT --reject-with icmp-host-prohibited']
        ipv6_rules += ['-j REJECT --reject-with icmp6-adm-prohibited']
    def _do_dhcp_rules(self, ipv4_rules, network_info):
        # Allow DHCP connections
        for ip in network_info:
            if ip['address'] == FLAGS.dhcp_listen_address:
                ipv4_rules += ['-s %s -p udp --sport 67 --dport 68 -j ACCEPT' %
                               ip['address']]
                ipv4_rules += ['-d %s -p udp --sport 68 --dport 67 -j ACCEPT' %
                               ip['address']]
                if FLAGS.use_ipv6:
                    ipv6_rules += ['-s %s -p udp --sport 547 --dport 546 -j ACCEPT' %
                                  ip['address']]
                    ipv6_rules += ['-d %s -p udp --sport 546 --dport 547 -j ACCEPT' %
                                  ip['address']]
    def _do_project_network_rules(self, ipv4_rules, ipv6_rules,
                                 network_info):
        # Allow connections to metadata server
        if FLAGS.use_ipv6:
            ipv4_rules += ['-s %s -p tcp -m tcp --dport 80 -j ACCEPT' %
                          FLAGS.dhcp_listen_address]
            ipv6_rules += ['-s %s -p tcp -m tcp --dport 80 -j ACCEPT' %
                          FLAGS.dhcp_listen_address]
        else:
            ipv4_rules += ['-s %s -p tcp -m tcp --dport 80 -j ACCEPT' %
                          FLAGS.metadata_address]
    def _do_ra_rules(self, ipv6_rules, network_info):
        # Allow ICMPv6 RA
        for ip in network_info:
            ipv6_rules += ['-p icmpv6 -j ACCEPT',
                          '-p icmpv6 --icmpv6-type 130 -j ACCEPT',
                          '-p icmpv6 --icmpv6-type 131 -j ACCEPT',
                          '-p icmpv6 --icmpv6-type 132 -j ACCEPT',
                          '-p icmpv6 --icmpv6-type 135 -j ACCEPT',
                          '-p icmpv6 --icmpv6-type 136 -j ACCEPT',
                          '-i %s -p icmpv6 -j ACCEPT' % ip['dev']]
    def _build_icmp_rule(self, rule, version):
        icmp_type = rule['from_port']
        icmp_code = rule['to_port']

        icmp_data = []
        if icmp_type == -1:
            icmp_type_code = None
        else:
            icmp_type_code = icmp_type
            if icmp_code == -1:
                icmp_data = ['--icmpv6-type %s' % icmp_type_code]
            else:
                icmp_type_code = '%s/%s' % (icmp_type_code, icmp_code)
                icmp_data = ['--icmpv6-type %s' % icmp_type_code]

        args = ['-p icmp']
        if version == 4:
            args += ['-j ACCEPT']
            if icmp_type_code:
                args += ['--icmp-type', icmp_type_code]
        else:
            args += ['-j ACCEPT']
            if icmp_type_code:
                args += icmp_data

        return args
    def _build_tcp_udp_rule(self, rule, version):
        args = ['-p tcp']
        if rule['from_port'] == rule['to_port']:
            args += ['--dport', '%s' % (rule['from_port'],)]
        else:
            args += ['-m', 'multiport', '--dports',
                     '%s:%s' % (rule['from_port'], rule['to_port'])]
        if rule['protocol'] in ['udp', 'tcp']:
            args += ['-j ACCEPT']
        else:
            raise NotImplementedError(
                _("Only UDP/TCP is supported with icmp IP protocols."))
        return args
