import ast
from vy_ast import *


def parse_body(stmt, context):
    nodes = []
    for node in stmt:
        nodes.append(parse_stmt(node, context))
    return nodes


def parse_stmt(stmt, context):
    if isinstance(stmt, ast.Pass):
        return ["pass"]

    elif isinstance(stmt, ast.If):
        cond = parse_value_expr(stmt.test, context)
        body = parse_body(stmt.body, context)
        if stmt.orelse:
            other_body = parse_body(stmt.orelse, context)
            return ["if", cond, body, other_body]
        return ["if", cond, body]

    elif isinstance(stmt, ast.Expr):
        return parse_expr(stmt.value, context)

    elif isinstance(stmt, ast.Return):
        if stmt.value:
            return ["seq", ["mstore", context.return_offset, parse_value_expr(stmt.value, context)]]
        return ["return", [0]]

    elif isinstance(stmt, ast.Assign):
        if len(stmt.targets) != 1:
            raise StructureException("Assignment has too many targets", stmt)
        target = parse_variable_location(stmt.targets[0], context)
        value = parse_value_expr(stmt.value, context)
        if not isinstance(target, IRNode):
            raise StructureException("Invalid assignment location", stmt)
        if isinstance(target, TupleNode):
            if not isinstance(value, TupleNode):
                raise StructureException("Tuple assignment to single location", stmt)
            if len(target.tuple_members) != len(value.tuple_members):
                raise StructureException("Tuple unpacking count mismatch", stmt)
            return ["seq"] + [
                ["seq", parse_set_variable(target.tuple_members[i], value.tuple_members[i], context)]
                for i in range(len(target.tuple_members))
            ]
        return parse_set_variable(target, value, context)

    elif isinstance(stmt, ast.AnnAssign):
        if stmt.value:
            raise StructureException("AnnAssign is invalid, use regular assignment", stmt)
        target = parse_variable_location(stmt.target, context)
        if not isinstance(target, IRNode):
            raise StructureException("Invalid assignment location", stmt)
        if isinstance(target, TupleNode):
            raise StructureException("TupleDeclaration is not a valid data declaration", stmt)
        var_type = parse_type(stmt.annotation, location="memory")
        return ["mstore", target, parse_value_expr(stmt.annotation, context)]

    elif isinstance(stmt, ast.AugAssign):
        if not isinstance(stmt.target, ast.Name):
            raise StructureException("Can only do augmented assignment on variables", stmt)
        lhs = parse_variable_location(stmt.target, context)
        if not isinstance(lhs, IRNode):
            raise StructureException("Invalid assignment location", stmt)
        rhs = parse_value_expr(stmt.value, context)
        if isinstance(stmt.op, ast.Div):
            ops = ["div", rhs]
        elif isinstance(stmt.op, ast.Mult):
            ops = ["mul", rhs]
        elif isinstance(stmt.op, ast.Mod):
            ops = ["mod", rhs]
        elif isinstance(stmt.op, ast.Add):
            ops = ["add", rhs]
        elif isinstance(stmt.op, ast.Sub):
            ops = ["sub", rhs]
        else:
            raise StructureException("Unsupported operator for augassign", stmt.op)
        return ["seq", parse_set_variable(lhs, Expr(ops, context), context)]

    elif isinstance(stmt, ast.While):
        if not isinstance(stmt.test, Expr):
            raise StructureException("While is not an expression", stmt.test)
        ops = parse_value_expr(stmt.test, context)
        body = parse_body(stmt.body, context)
        if stmt.orelse:
            other_body = parse_body(stmt.orelse, context)
            return ["while", ops, body, other_body]
        return ["while", ops, body]

    elif isinstance(stmt, ast.Raise):
        if isinstance(stmt.exc, ast.Call):
            if stmt.exc.func.id in ("invalid", "revert", "assert_modifiable"):
                raise StructureException("Cannot use %s in a protected function" % stmt.exc.func.id, stmt.exc)
        return ["assert_invalid", Expr(stmt.exc, context)]

    elif isinstance(stmt, ast.For):
        if not isinstance(stmt.target, ast.Name):
            raise StructureException("For loop index needs to be a variable, not an expression

