        if self._type == ParseState.PARSE_UNTIL_EOF:
            return self.payload.feed_eof()
        else:
            return None
    def exception(self) -> Optional[BaseException]:
        return self.payload.exception()
    def set_exception(self, exc: BaseException) -> None:
        self.payload.set_exception(exc)
    def set_parser(
        self, type: ParseState, *, parser: Optional[Any] = None, payload: Optional[Any] = None
    ) -> None:
        if payload is None:
            payload = self.payload
        if type == ParseState.PARSE_LENGTH:
            self._length = length
            self._payload = payload
            self._type = type
        elif type == ParseState.PARSE_CHUNKED:
            self._payload = payload
            self._type = type
        elif type == ParseState.PARSE_UNTIL_EOF:
            self._payload = payload
            self._type = type
        else:
            raise ValueError("Invalid parser type: %r" % type)
    @property
    def completed(self) -> bool:
        return self._type in (ParseState.PARSE_LENGTH, ParseState.PARSE_UNTIL_EOF)
    def begin_http_body_parsing(
        self,
        message: RawRequestMessage,
        payload: Any,
        *,
        _READALL: bool = False,
        _CHUNKED: bool = False,
        _LENGTH: Optional[int] = None,
        _CONTENT_LENGTH: istr = hdrs.CONTENT_LENGTH,
        _TRANSFER_ENCODING: istr = hdrs.TRANSFER_ENCODING,
        _CONNECTION: istr = hdrs.CONNECTION,
        _CONTENT_TYPE: istr = hdrs.CONTENT_TYPE,
        _EMPTY_PAYLOAD: Optional[EmptyPayload] = None,
        _payload_writer: Any = None,
        _message_complete: bool = False,
        _payload_keep_alive: bool = False,
        _payload_type: Type[Any] = HttpPayloadParser,
    ) -> Tuple[Any, Optional[bool], Optional[bool]]:
        if _CONTENT_LENGTH in message.headers:
            length = int(message.headers[_CONTENT_LENGTH])
            if length:
                p = _payload_type(
                    payload,
                    message.method,
                    message.version,
                    length,
                    _message_complete,
                    _payload_keep_alive,
                )
            else:
                if _EMPTY_PAYLOAD is None:
                    p = EmptyPayload()
                else:
                    p = _EMPTY_PAYLOAD
        elif _TRANSFER_ENCODING in message.headers:
            if message.version == HttpVersion10:
                return payload, False, False
            elif _CHUNKED:
                p = _payload_type(payload, message.method, message.version, _message_complete, _payload_keep_alive)
