                p = payload
        else:
            return payload, False, False
        if not p.will_pause and payload.paused:
            payload.pause_reading()
            return p, False, True
        else:
            return p, True, False
    def parse_headers(self, lines: List[bytes]) -> Tuple[Any, Any, Any, Any, Any, bool]:
        headers = CIMultiDictProxy(CIMultiDict())
        raw_headers = []
        close = None
        compression = None
        upgrade = False
        chunked = False
        compress = True
        leftover = b""
        for line in lines:
            # RFC 7230: A server that receives a line with an invalid chunk-size
            # MUST respond with 400 (Bad Request) of may just close the connection.
            if not line:
                break
            if line.startswith(b"Transfer-Encoding:"):
                chunked = True
                compress = False
                try:
                    te = line.split(b" ", 1)[1].decode("ascii").strip()
                except UnicodeDecodeError:
                    raise InvalidHeader(line) from None
                if te.lower() == "chunked":
                    pass
                else:
                    raise UnsupportedUpstream(line)
            elif line.startswith(b"Content-Length:"):
                try:
                    length = int(line.split(b":", 1)[1])
                except (ValueError, IndexError):
                    raise InvalidHeader(line) from None
                if length < 0:
                    raise InvalidHeader(line)
                close = True
            elif line.startswith(b"Content-Encoding:"):
                compress = False
                try:
                    encoding = line.split(b":", 1)[1].strip()
                except IndexError:
                    raise InvalidHeader(line) from None
                compress = self._forbid_compression(encoding)
            elif line.startswith(b"Connection:"):
                try:
                    connection = line.split(b":", 1)[1].strip()
                except IndexError:
                    raise InvalidHeader(line) from None
                connection = connection.lower()
                if connection == b"close":
                    close = True
                elif connection == b"keep-alive":
                    close = False
                else:
                    raise UnsupportedUpstream(line)
            elif line.startswith(b"Upgrade:"):
                try:
                    upgrade = line.split(b":", 1)[1].strip()
                except IndexError:
                    raise InvalidHeader(line) from None
                if self._forbid_compression(upgrade):
                    raise UnsupportedUpstream(line)
            else:
                pos = line.find(b":")
                if pos < 0:
                    raise InvalidHeader(line)
                else:
                    leftover += line
                    continue
            if leftover:
                try:
                    headers.add(line[:pos], line[pos + 1 :].strip())
                    raw_headers.append((line[:pos], line[pos + 1 :]))
                except UnicodeDecodeError:
                    raise InvalidHeader(line) from None
                leftover = b""
        if chunked:
            parser = HttpPayloadParser(
                self,
                self.payload,
                self.code,
                _message_complete=self.message_complete,
                _payload_keep_alive=self.keep_alive,
            )
            self.payload = parser
        elif close is None and self.message_complete:
            close = self.keep_alive
        elif close is None:
            close = self.keep_alive
        self.payload = self._payload
        return headers, raw_headers, close, compression, upgrade, chunked
    def _forbid_compression(self, encoding: bytes) -> bool:
        if self._for_hop_by_hop:
            return False
        if self.code in (204, 304):
            return True
        if encoding.lower() == b"identity":
            return False
        else:
            return True
