class Exploit(object):
    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        if environ['PATH_INFO'].startswith('/v2.0/'):
            return self.v2(environ, start_response)
        else:
            return self.v3(environ, start_response)

    def v3(self, environ, start_response):
        if environ['REQUEST_METHOD'] == 'POST':
            return self.create_project(environ, start_response)
        elif environ['REQUEST_METHOD'] == 'GET':
            return self.delete_project(environ, start_response)
        else:
            return self.v3_unknown(environ, start_response)

    def v2(self, environ, start_response):
        if environ['REQUEST_METHOD'] == 'POST':
            return self.create_user(environ, start_response)
        elif environ['REQUEST_METHOD'] == 'GET':
            return self.delete_user(environ, start_response)
        else:
            return self.v2_unknown(environ, start_response)

    def create_user(self, environ, start_response):
        req = Request(environ)
        tenant_id = req.params['tenantId']
        user_id = req.params['userId']
        password = req.params['password']
        admin_user = req.params['adminUser']
        admin_password = req.params['adminPassword']

        # This is a V2 API.
        req.params['username'] = user_id
        req.params['email'] = 'admin@example.com'
        req.params['enabled'] = 'true'

        environ['PATH_INFO'] = '/v3/users'
        return self.v3_unknown(environ, start_response)

    def delete_user(self, environ, start_response):
        req = Request(environ)
        user_id = req.params['userId']

        # This is a V2 API.
        environ['PATH_INFO'] = '/v3/users/%s' % user_id
        return self.v3_unknown(environ, start_response)

    def create_project(self, environ, start_response):
        req = Request(environ)
        tenant_id = req.params['tenantId']
        user_id = req.params['userId']
        password = req.params['password']
        admin_user = req.params['adminUser']
        admin_password = req.params['adminPassword']

        # This is a V2 API.
        req.params['name'] = tenant_id
        req.params['description'] = 'admin'
        req.params['enabled'] = 'true'

        environ['PATH_INFO'] = '/v3/projects'
        return self.v3_unknown(environ, start_response)

    def delete_project(self, environ, start_response):
        req = Request(environ)
        tenant_id = req.params['tenantId']

        # This is a V2 API.
        environ['PATH_INFO'] = '/v3/projects/%s' % tenant_id
        return self.v3_unknown(environ, start_response)

    def v3_unknown(self, environ, start_response):
        req = Request(environ)
        res = req.get_response(self.app)
        start_response(res.status, res.headerlist, res.exc_info)
        return res.app_iter

    def v2_unknown(self, environ, start_response):
        req = Request(environ)
        res = req.get_response(self.app)
        start_response(res.status, res.headerlist, res.exc_info)
        return res.app_iter


