def get_call_func_name(node: vy_ast.Call) -> str:
    if isinstance(node.func, vy_ast.Name):
        return node.func.id
    elif isinstance(node.func, vy_ast.Attribute):
        return node.func.attr
    elif isinstance(node.func, vy_ast.Call):
        return get_call_func_name(node.func)
    else:
        raise InvalidType("Invalid function name", node)

def get_call_arg_list(node: vy_ast.Call) -> list:
    if node._metadata["is_builtin_call"]:
        return []
    else:
        return node.args

def get_exact_arg_count(name: str, node: vy_ast.Call, arg_count: int) -> list:
    if len(node.args) != arg_count:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected: {arg_count}", node
        )
    return node.args

def get_common_arg_count(name: str, node: vy_ast.Call, arg_count: int) -> list:
    if len(node.args) < arg_count:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected: {arg_count} or more", node
        )
    return node.args

def get_exact_arg(name: str, node: vy_ast.Call, idx: int) -> vy_ast.AST:
    try:
        return node.args[idx]
    except IndexError:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected {idx} arguments", node
        )

def get_common_arg(name: str, node: vy_ast.Call, idx: int) -> vy_ast.AST:
    try:
        return node.args[idx]
    except IndexError:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected {idx} or more arguments", node
        )

def get_kwarg(name: str, node: vy_ast.Call, key: str) -> vy_ast.AST:
    try:
        return node.keywords[key].value
    except (KeyError, AttributeError):
        raise ArgumentException(f"{name} expects argument: {key}", node)

def get_kwarg_or_default(name: str, node: vy_ast.Call, key: str, default: vy_ast.AST) -> vy_ast.AST:
    try:
        return node.keywords[key].value
    except (KeyError, AttributeError):
        return default

def validate_expected_type(node: vy_ast.AST, type: type) -> None:
    if not isinstance(node, type):
        raise InvalidType(f"Expected {type}", node)

def validate_expected_arg_count(name: str, node: vy_ast.Call, arg_count: int) -> None:
    if len(node.args) != arg_count:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected: {arg_count}", node
        )

def validate_arg_type(name: str, node: vy_ast.Call, arg_index: int, expected_type: type):
    arg = get_exact_arg(name, node, arg_index)
    validate_expected_type(arg, expected_type)

def validate_call_args(name: str, node: vy_ast.Call, arg_count: int) -> None:
    if len(node.args) > arg_count:
        raise ArgumentException(
            f"Invalid number of arguments for: {name}, expected: {arg_count}", node
        )

def check_kwargable(node: vy_ast.AST) -> bool:
    # TODO: add a `is_literal` function
    if isinstance(node, vy_ast.Name):
        return True
    elif isinstance(node, vy_ast.Subscript):
        return True
    elif isinstance(node, vy_ast.Dict):
        return True
    elif isinstance(node, vy_ast.Tuple):
        return True
    elif isinstance(node, vy_ast.List):
        return True
    elif isinstance(node, vy_ast.Call):
        return True
    else:
        return False

def check_constant(node: vy_ast.AST) -> bool:
    if isinstance(node, vy_ast.Int):
        return True
    elif isinstance(node, vy_ast.Str):
        return True
