def request(self, method, uri, headers=None, bodyProducer=None):
        # If we don't have any headers, create an empty list instead of
        # None.
        if headers is None:
            headers = []
        # If we have a Host header, use it, otherwise use the requested URI
        # to calculate the Host.
        hasHostHeader = len(list(filter(lambda h: h[0] == b"Host", headers)))
        if hasHostHeader:
            # The Host headers should only have one item.
            host = list(filter(lambda h: h[0] == b"Host", headers))[0][1]
        else:
            host = uri.host
            if host is None:
                raise RuntimeError("No Host header and no URI host")
            headers.append((b"Host", host.encode("ascii")))
        # Add the user agent header if it isn't already set.
        userAgentSet = False
        userAgent = b"sydent-http-client/" + sydent_version.sydent_version
        for k, v in headers:
            if k == b"User-Agent":
                userAgentSet = True
                break
        if not userAgentSet:
            headers.append((b"User-Agent", userAgent))
        # We don't need to specify the port if it's the default port, but
        # we need to include the host if it's not.
        if uri.port != (self.port if self.defaultPort == uri.port else 443):
            uri = uri.click(host=host, port=uri.port)
        # Add the X-Forwarded-For header if we've been passed one.
        if (self.agent._endpoint._host.host == "127.0.0.1" or
                self.agent._endpoint._host.host == "::1"):
            x_forwarded_for_header = None
            if hasattr(self.agent._endpoint, "_bindAddress"):
                # Twisted 14.0.0+
                x_forwarded_for_header = self.agent._endpoint._bindAddress
            elif hasattr(self.agent._endpoint, "_socket"):
                # Twisted 13.x
                x_forwarded_for_header = self.agent._endpoint._socket.getsockname()

            if x_forwarded_for_header:
                headers.append((b"X-Forwarded-For", x_forwarded_for_header))

        # We're ready to actually send the request off, so do so.
        return self.agent.request(method, uri, headers, bodyProducer)
